implementation_steps.step:
在 src/coach/agent.py 的 __init__ 中添加：
```python # Phase 5: 语义安全三件套（延迟加载） self._counterfactual = None self._cross_track = None self._precedent = None self._data_source = None # facts 表查询用 ```
新增属性方法： ```python @property def counterfactual(self): if self._counterfactual is None: cfg = _coach_cfg.get("counterfactual", {}) if cfg.get("enabled", False): from src.coach.counterfactual import CounterfactualSimulator self._counterfactual = CounterfactualSimulator(cfg) return self._counterfactual
@property def cross_track(self): if self._cross_track is None: from src.coach.cross_track import CrossTrackChecker self._cross_track = CrossTrackChecker() return self._cross_track
@property def precedent(self): if self._precedent is None: cfg = _coach_cfg.get("precedent_intercept", {}) if cfg.get("enabled", False): from src.coach.precedent_intercept import PrecedentInterceptor from src.coach.data import TripleLayerGraph self._data_source = TripleLayerGraph() self._precedent = PrecedentInterceptor(cfg, data_source=self._data_source) return self._precedent ```
注意：cross_track 始终可用（不依赖 enabled 配置，因为跨轨检查是轻量纯函数）。 counterfactual 和 precedent 遵循 enable 配置。

在 act() 中 compose() 调用之后、DSL 构建之前插入：

```python
# 4e. compose() 已在步骤 4 完成
#    此时 action 已包含升级后的 domain_passport

# 4f. Phase 5: 反事实仿真（默认关闭）
counterfactual_result = None
try:
    if self.counterfactual:
        user_ctx = {"state": user_state}
        counterfactual_result = self.counterfactual.simulate(action, user_ctx)
        # 高风险动作：降级处理
        if counterfactual_result.get("recommendation") == "block":
            action["action_type"] = "reflect"
            action["payload"] = {
                "question": f"这个动作风险较高，是否确认？{intent}",
                "context_ids": [],
                "format": "text",
            }
except Exception:
    pass

# 4g. Phase 5: 跨轨一致性检查（始终可用）
cross_track_result = None
try:
    dominant_layer = user_state.get("dominant_layer", "L0")
    cross_track_result = self.cross_track.check(
        action.get("action_type", ""), dominant_layer,
    )
    # 高严重度偏离：记录告警
    if cross_track_result.get("severity") == "high":
        correction = self.cross_track.suggest_correction(
            action.get("action_type", ""), dominant_layer,
        )
        if correction.get("needs_correction") and correction.get("suggested_action"):
            action["action_type"] = correction["suggested_action"]
except Exception:
    pass

# 4h. Phase 5: 失败先例拦截（默认关闭）
precedent_result = None
try:
    if self.precedent:
        passport = action.get("domain_passport", {})
        precedent_result = self.precedent.intercept(
            intent=intent,
            domain=passport.get("domain", "general"),
            action_type=action.get("action_type", ""),
        )
        # 命中断：阻止当前动作
        if precedent_result.get("hit") and precedent_result.get("action") == "block":
            action["action_type"] = "defer"
            action["payload"] = {
                "reason": precedent_result.get("reason", "命中失败先例"),
                "fallback_intensity": "minimal",
                "resume_condition": "用户主动要求恢复",
            }
except Exception:
    pass
```

将三件套输出附加到 result dict：
```python
result = {
    ...
    "counterfactual_result": counterfactual_result,
    "cross_track_result": cross_track_result,
    "precedent_result": precedent_result,
}
```

注意：所有调用包裹在 try/except 中，防止模型异常阻断主流程。
